// Aggregate all task data into a single summary object
const items = $input.all();

const completed = [];
const inProgress = [];

for (const item of items) {
  const props = item.json.properties || item.json;
  const title = props.Name?.title?.[0]?.plain_text || props.title || 'Untitled';
  const project = props.Project?.select?.name || 'No Project';
  const priority = props.Priority?.select?.name || 'Medium';
  const status = props.Status?.select?.name || 'Unknown';

  if (status === 'Done') {
    completed.push({ title, project, priority });
  } else {
    inProgress.push({ title, project, priority });
  }
}

return [{
  json: {
    date: new Date().toISOString().split('T')[0],
    completed_count: completed.length,
    in_progress_count: inProgress.length,
    completed,
    in_progress: inProgress
  }
}];

